import{_ as a,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Drill Search","description":"","frontmatter":{},"headers":[],"relativePath":"training/drill-search.md","filePath":"training/drill-search.md"}'),l={name:"training/drill-search.md"};function o(n,e,s,c,h,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="drill-search" tabindex="-1">Drill Search <a class="header-anchor" href="#drill-search" aria-label="Permalink to &quot;Drill Search&quot;">​</a></h1><p>Every suggestion card and training plan includes a <strong>Find Drills</strong> button that opens a YouTube drill search pre-populated with sport-specific search terms.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Tapping <strong>Find Drills</strong> opens YouTube (or your default browser) with a pre-built search query based on:</p><ul><li>The sport (baseball or softball)</li><li>The training area (pitching, hitting, fielding, baserunning)</li><li>The specific focus area (e.g. &quot;arm path&quot;, &quot;hip rotation&quot;, &quot;changeup command&quot;)</li></ul><p>For example a suggestion about a softball pitcher&#39;s rise ball command generates a search like: <code>softball pitcher rise ball command drills youth coaching</code></p><h2 id="sport-awareness" tabindex="-1">Sport Awareness <a class="header-anchor" href="#sport-awareness" aria-label="Permalink to &quot;Sport Awareness&quot;">​</a></h2><p>Drill searches are fully sport-aware. Softball teams never see baseball-specific results as the default. The search terms are tuned for youth coaching context — not professional or college-level instruction.</p><h2 id="saving-drill-references" tabindex="-1">Saving Drill References <a class="header-anchor" href="#saving-drill-references" aria-label="Permalink to &quot;Saving Drill References&quot;">​</a></h2><p>After finding a useful drill:</p><ol><li>Copy the YouTube URL</li><li>Return to the training plan</li><li>Paste it in the <strong>Drills</strong> notes field</li></ol><p>This creates a permanent reference to the drill within the plan.</p><h2 id="drill-search-does-not-require-an-account" tabindex="-1">Drill Search Does Not Require an Account <a class="header-anchor" href="#drill-search-does-not-require-an-account" aria-label="Permalink to &quot;Drill Search Does Not Require an Account&quot;">​</a></h2><p>The Find Drills button opens YouTube in your browser — it does not require a YouTube account or any additional setup. Results vary based on YouTube&#39;s search algorithm and available content.</p>',14)])])}const b=a(l,[["render",o]]);export{p as __pageData,b as default};
